import pika

logging.basicConfig(
    level=os.getenv("LOG_LEVEL", "INFO").upper(),
    format="%(asctime)s %(levelname)s %(message)s",
)

RABBITMQ_URL = os.getenv("RABBITMQ_URL", "amqp://guest:guest@localhost:5672/%2F")
QUEUE_NAME = os.getenv("QUEUE_NAME", "jobs")
PREFETCH_COUNT = int(os.getenv("PREFETCH_COUNT", "1"))
REQUEUE_ON_FAILURE = os.getenv("REQUEUE_ON_FAILURE", "true").lower() in {"1", "true", "yes", "y"}

stop_requested = False


def handle_signal(signum, frame):
    global stop_requested
    stop_requested = True
    logging.info("Shutdown requested")


def execute_command(command: str) -> int:
    result = subprocess.run(command, shell=True)
    return result.returncode


def on_message(ch, method, properties, body):
    command = body.decode("utf-8", errors="replace").strip()
    logging.info("Received job: %s", command)

    try:
        return_code = execute_command(command)
        if return_code == 0:
            ch.basic_ack(delivery_tag=method.delivery_tag)
            logging.info("Job completed successfully")
        else:
            logging.error("Job failed with exit code %s", return_code)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=REQUEUE_ON_FAILURE)
    except Exception:
        logging.exception("Job execution error")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=REQUEUE_ON_FAILURE)


def main():
    signal.signal(signal.SIGINT, handle_signal)
    signal.signal(signal.SIGTERM, handle_signal)

    params = pika.URLParameters(RABBITMQ_URL)
    connection = pika.BlockingConnection(params)
